import{V as o}from"./chunks/theme.CBnMlhxj.js";import{c as t,o as i,j as a,a2 as n,a as r,G as l,k as s}from"./chunks/framework.DDIT__tB.js";const d={class:"tip custom-block"},u=JSON.parse('{"title":"📊 Model: (InformationFlow-FriendMap-no-violation)","description":"","frontmatter":{},"headers":[],"relativePath":"examples/models/dfd/IF-FriendMap-no-violation.md","filePath":"examples/models/dfd/IF-FriendMap-no-violation.md"}'),c={name:"examples/models/dfd/IF-FriendMap-no-violation.md"},b=Object.assign(c,{setup(h){return(p,e)=>(i(),t("div",null,[e[2]||(e[2]=a("h1",{id:"📊-model-informationflow-friendmap-no-violation",tabindex:"-1"},[r("📊 Model: (InformationFlow-FriendMap-no-violation) "),a("a",{class:"header-anchor",href:"#📊-model-informationflow-friendmap-no-violation","aria-label":'Permalink to "📊 Model: (InformationFlow-FriendMap-no-violation)"'},"​")],-1)),a("div",d,[e[0]||(e[0]=a("p",{class:"custom-block-title"},"Available Online",-1)),e[1]||(e[1]=a("p",null,"This model is available to view using the online editor!",-1)),l(s(o),{text:"Open In Online Editor",href:"https://editor.dataflowanalysis.org/?file=https://raw.githubusercontent.com/DataFlowAnalysis/DataFlowAnalysis/refs/heads/main/bundles/org.dataflowanalysis.examplemodels/scenarios/dfd/IF-FriendMap-no-violation/FriendMap-no-violation.json"})]),e[3]||(e[3]=n('<h2 id="🔗-link-to-original-paper-article" tabindex="-1">🔗 Link to Original Paper/Article <a class="header-anchor" href="#🔗-link-to-original-paper-article" aria-label="Permalink to &quot;🔗 Link to Original Paper/Article&quot;">​</a></h2><p><a href="https://ieeexplore.ieee.org/document/8703905" target="_blank" rel="noreferrer">View Source</a><a href="https://github.com/DataFlowAnalysis/DataFlowAnalysis/tree/main/bundles/org.dataflowanalysis.examplemodels/scenarios/dfd/IF-FriendMap-no-violation" target="_blank" rel="noreferrer">Open Example Model in Example Models Bundle</a></p><h2 id="📝-short-description" tabindex="-1">📝 Short Description <a class="header-anchor" href="#📝-short-description" aria-label="Permalink to &quot;📝 Short Description&quot;">​</a></h2><p>The case is about visualizing the locations of friends in a map and posting it on a social network.</p><h2 id="🔤-abbreviations" tabindex="-1">🔤 Abbreviations <a class="header-anchor" href="#🔤-abbreviations" aria-label="Permalink to &quot;🔤 Abbreviations&quot;">​</a></h2><ul><li><code>SNAPP</code>: Social Network App</li><li><code>Local DS</code>: Local DataStore</li></ul><h2 id="📖-extensive-description" tabindex="-1">📖 Extensive Description <a class="header-anchor" href="#📖-extensive-description" aria-label="Permalink to &quot;📖 Extensive Description&quot;">​</a></h2><p>The user <code>Alice</code> reads friend locations (<em>location_bob</em> and <em>location_alice</em>) from a <strong>SNAPP</strong> and stores them in a <strong>Local DS</strong>. Afterwards, the system loads <em>map_code</em> from a <strong>Map Provider</strong> and the <strong>Friend Map</strong> app. The code uses <code>Google</code> to create the map. Alice posts this map on the <code>SocialNetwork</code>. The majority of the components are located in a <code>Trust</code> <strong>Zone</strong>. When creating a map, data flows through <code>Google</code>, which is located in the <code>Attack</code> <strong>Zone</strong>. This is why data is encrypted and decrypted around <code>Google</code>.</p><h2 id="🏷️-label-description" tabindex="-1">🏷️ Label Description <a class="header-anchor" href="#🏷️-label-description" aria-label="Permalink to &quot;🏷️ Label Description&quot;">​</a></h2><h3 id="🗂️-data-labels" tabindex="-1">🗂️ Data Labels: <a class="header-anchor" href="#🗂️-data-labels" aria-label="Permalink to &quot;🗂️ Data Labels:&quot;">​</a></h3><ul><li><strong>Level</strong>: There are two types of levels: <code>High</code> and <code>Low</code>. <code>High</code> dominates <code>Low</code>.</li></ul><h3 id="🏷️-node-labels" tabindex="-1">🏷️ Node Labels: <a class="header-anchor" href="#🏷️-node-labels" aria-label="Permalink to &quot;🏷️ Node Labels:&quot;">​</a></h3><ul><li><strong>Actor</strong>: There are four actors in this model: <code>Google</code>, <code>Alice</code>, <code>SocialNetwork</code> and <code>CreateMap</code>. A node is not nessecarily part of a zone.</li><li><strong>Zone</strong>: There are two zones in this model: <code>Attack</code> and <code>Trust</code>. A node always part of one of these zones.</li></ul><h2 id="⚠️-constraints" tabindex="-1">⚠️ Constraints <a class="header-anchor" href="#⚠️-constraints" aria-label="Permalink to &quot;⚠️ Constraints&quot;">​</a></h2><h3 id="safety" tabindex="-1">Safety <a class="header-anchor" href="#safety" aria-label="Permalink to &quot;Safety&quot;">​</a></h3><p>System parts or actors in the attack zone must not have access to data classified <code>High</code>:</p><ul><li><code>Safety: data Level.High neverFlows vertex Zone.Attack</code></li></ul><h2 id="🚨-violations" tabindex="-1">🚨 Violations <a class="header-anchor" href="#🚨-violations" aria-label="Permalink to &quot;🚨 Violations&quot;">​</a></h2><p>None.</p>',19))]))}});export{u as __pageData,b as default};
